/**
 * Initialize all shared state used by GrovePi 1.
 * This node should run once on startup.
 */
const now = Date.now();

const defaults = {
    armed: false,
    securityState: "inactive", // inactive | active | suspicious | alarm | resolved
    resolvedUntil: null,
    settings: {
        suspiciousModeEnabled: true,
        seatDeltaCm: 10,
        seatDebounceMs: 1200,
        vibrationSpike: 1,
        accelMagSpike: 1.8,
        confirmWindowMs: 4000,
        suspiciousTimeoutMs: 60000,
        alarmMinMs: 15000,
        autoResolveQuietMs: 6000,
        notificationPhone: "",
        notificationEmail: ""
    },
    baseline: {
        distanceCm: null,
        capturedAt: null
    },
    last: {
        distanceCm: null,
        distanceAt: null,
        temperatureC: null,
        humidity: null,
        climateAt: null,
        vibration: null,
        vibrationAt: null,
        accelMag: null,
        accelAt: null
    },
    intrusion: {
        id: null,
        startedAt: null,
        lastEvidenceAt: null,
        confirmedBy: [],
        status: "closed",
        picturePath: null,
        videoPath: null,
        videoActive: false,
        note: null,
        closedAt: null
    },
    alarm: {
        active: false,
        tickCount: 0,
        ledState: 0
    },
    liveFeedEvents: [],
    seatStableSince: null
};

for (const [key, value] of Object.entries(defaults)) {
    if (flow.get(key) === undefined) {
        flow.set(key, value);
    }
}

node.status({
    fill: "grey",
    shape: "dot",
    text: `armed=${flow.get("armed")} state=${flow.get("securityState")}`
});

msg.payload = {
    ok: true,
    armed: flow.get("armed"),
    state: flow.get("securityState"),
    ts: now
};

return msg;

/**
 * Arm or disarm the system.
 * When arming, the baseline is cleared and recaptured from the latest ultrasonic reading.
 * When disarming, any active alarm devices are explicitly shut down.
 * Preserves the original HTTP message for the http response node.
 */
const now = Date.now();
const body = msg.payload || {};
const armed = Boolean(body.armed);

flow.set("armed", armed);
flow.set("seatStableSince", null);
flow.set("resolvedUntil", null);

let alarmControlMsg = null;

if (!armed) {
    flow.set("securityState", "inactive");
    flow.set("baseline", { distanceCm: null, capturedAt: null });
    flow.set("intrusion", {
        id: null,
        startedAt: null,
        lastEvidenceAt: null,
        confirmedBy: [],
        status: "closed",
        picturePath: null,
        videoPath: null,
        videoActive: false,
        note: null,
        closedAt: now
    });
    flow.set("alarm", { active: false, tickCount: 0, ledState: 0 });

    alarmControlMsg = RED.util.cloneMessage(msg);
    alarmControlMsg.event = {
        type: "ALARM_OFF",
        reason: "system_disarmed",
        note: "System disarmed by user",
        intrusionId: null,
        evidence: [],
        state: "inactive",
        ts: now
    };
    alarmControlMsg.statusUpdate = {
        armed: false,
        state: "inactive",
        intrusionId: null,
        evidence: [],
        ts: now
    };
} else {
    flow.set("securityState", "active");
    flow.set("baseline", { distanceCm: null, capturedAt: null });
}

const mqttMsg = RED.util.cloneMessage(msg);
mqttMsg.topic = "vehicle/security/status";
mqttMsg.payload = {
    armed,
    state: flow.get("securityState"),
    baseline: flow.get("baseline"),
    ts: now
};

const baselineMsg = RED.util.cloneMessage(msg);
baselineMsg.payload = {
    armed,
    captureBaseline: armed,
    ts: now
};

msg.payload = {
    ok: true,
    armed,
    state: flow.get("securityState"),
    baseline: flow.get("baseline"),
    ts: now
};

return [msg, mqttMsg, baselineMsg, alarmControlMsg];

/**
 * Return current system status for the dashboard.
 */
const payload = {
    armed: Boolean(flow.get("armed")),
    state: flow.get("securityState") || "inactive",
    settings: flow.get("settings") || {},
    baseline: flow.get("baseline") || {},
    last: flow.get("last") || {},
    intrusion: flow.get("intrusion") || {},
    alarm: flow.get("alarm") || {},
    ts: Date.now()
};

msg.payload = payload;
return msg;

/**
 * Resolve an active suspicious/alarm incident from the dashboard.
 * Keeps the original HTTP msg so the http response node can reply correctly.
 */
const now = Date.now();
const body = msg.payload || {};
const armed = Boolean(flow.get("armed"));
const intrusion = flow.get("intrusion") || {};

if (!armed) {
    msg.statusCode = 400;
    msg.payload = { ok: false, error: "System is not armed", ts: now };
    return [msg, null, null, null];
}

if (!intrusion.id || intrusion.status !== "open") {
    msg.statusCode = 409;
    msg.payload = { ok: false, error: "No active intrusion", ts: now };
    return [msg, null, null, null];
}

if (body.intrusionId && body.intrusionId !== intrusion.id) {
    msg.statusCode = 409;
    msg.payload = {
        ok: false,
        error: "Intrusion ID mismatch",
        activeIntrusionId: intrusion.id,
        requestedIntrusionId: body.intrusionId,
        ts: now
    };
    return [msg, null, null, null];
}

intrusion.status = "resolved";
intrusion.closedAt = now;
intrusion.note = body.note || "Resolved by user";

flow.set("intrusion", intrusion);
flow.set("securityState", "resolved");
flow.set("resolvedUntil", now + 5000);

const eventMsg = RED.util.cloneMessage(msg);
eventMsg.event = {
    type: "ALARM_OFF",
    reason: body.resolutionType || "user_resolved",
    note: intrusion.note,
    intrusionId: intrusion.id,
    evidence: intrusion.confirmedBy || [],
    picturePath: intrusion.picturePath || "",
    videoPath: intrusion.videoPath || "",
    state: "resolved",
    ts: now
};
eventMsg.statusUpdate = {
    armed: true,
    state: "resolved",
    intrusionId: intrusion.id,
    evidence: intrusion.confirmedBy || [],
    ts: now
};

const mqttMsg = RED.util.cloneMessage(msg);
mqttMsg.topic = "vehicle/security/status";
mqttMsg.payload = eventMsg.statusUpdate;

msg.statusCode = 200;
msg.payload = {
    ok: true,
    message: "Intrusion resolved",
    intrusionId: intrusion.id,
    state: "resolved",
    ts: now
};

return [msg, mqttMsg, eventMsg, eventMsg];

/**
 * Escalate an existing suspicious intrusion to alarm.
 * Keeps the original HTTP msg so the http response node can reply correctly.
 */
const now = Date.now();
const body = msg.payload || {};
const armed = Boolean(flow.get("armed"));
const intrusion = flow.get("intrusion") || {};
let state = flow.get("securityState") || "inactive";

if (!armed) {
    msg.statusCode = 400;
    msg.payload = { ok: false, error: "System is not armed", ts: now };
    return [msg, null, null, null];
}

if (!intrusion.id || intrusion.status !== "open") {
    msg.statusCode = 409;
    msg.payload = { ok: false, error: "No active intrusion available", ts: now };
    return [msg, null, null, null];
}

if (body.intrusionId && body.intrusionId !== intrusion.id) {
    msg.statusCode = 409;
    msg.payload = {
        ok: false,
        error: "Intrusion ID mismatch",
        activeIntrusionId: intrusion.id,
        requestedIntrusionId: body.intrusionId,
        ts: now
    };
    return [msg, null, null, null];
}

if (state !== "suspicious") {
    msg.statusCode = 409;
    msg.payload = {
        ok: false,
        error: `Cannot escalate from state ${state}`,
        ts: now
    };
    return [msg, null, null, null];
}

state = "alarm";
intrusion.lastEvidenceAt = now;
intrusion.confirmedBy = Array.from(
    new Set([...(intrusion.confirmedBy || []), "dashboard_confirmed"])
);

flow.set("securityState", state);
flow.set("intrusion", intrusion);

const eventMsg = RED.util.cloneMessage(msg);
eventMsg.event = {
    type: "ALARM_ON",
    reason: "user_requested_alarm",
    triggerSource: body.triggerSource || "dashboard_user_confirmation",
    note: body.note || "Alarm requested by dashboard",
    intrusionId: intrusion.id,
    evidence: intrusion.confirmedBy,
    picturePath: intrusion.picturePath || "",
    videoPath: intrusion.videoPath || "",
    armed: true,
    state: "alarm",
    ts: now
};
eventMsg.statusUpdate = {
    armed: true,
    state: "alarm",
    intrusionId: intrusion.id,
    evidence: intrusion.confirmedBy,
    ts: now
};

const mqttMsg = RED.util.cloneMessage(msg);
mqttMsg.topic = "vehicle/security/status";
mqttMsg.payload = eventMsg.statusUpdate;

msg.statusCode = 200;
msg.payload = {
    ok: true,
    message: "Alarm triggered",
    intrusionId: intrusion.id,
    state: "alarm",
    ts: now
};

return [msg, mqttMsg, eventMsg, eventMsg];

/**
 * Normalize DHT11 output and keep latest climate values in flow context.
 */
const now = Date.now();
const temperatureC = Number(msg.payload[0]);
const humidity = Number(msg.payload[1]);

const last = flow.get("last") || {};
last.temperatureC = temperatureC;
last.humidity = humidity;
last.climateAt = now;
flow.set("last", last);

node.send([
    {
        payload: {
            measurement: "vehicle_climate",
            tags: {
                device: "pi1",
                sensor: "dht11"
            },
            fields: {
                temperatureC,
                humidity
            },
            timestamp: new Date(now)
        }
    },
    {
        payload: {
            sensor: "dht11",
            temperatureC,
            humidity,
            ts: now
        }
    }
]);

return null;

/**
 * Normalize ultrasonic readings and store the latest distance reading.
 */
const now = Date.now();
const distanceCm = typeof msg.payload === "number"
    ? Number(msg.payload)
    : Number(msg.payload?.distance ?? msg.payload?.cm);

const last = flow.get("last") || {};
last.distanceCm = distanceCm;
last.distanceAt = now;
flow.set("last", last);

msg.payload = {
    sensor: "ultrasonic",
    distanceCm,
    ts: now
};

return msg;

/**
 * When the system is armed, capture the current distance as the driver-seat baseline.
 */
const now = Date.now();
const request = msg.payload || {};
const armed = Boolean(flow.get("armed"));
const last = flow.get("last") || {};

if (!armed || !request.captureBaseline) {
    return null;
}

if (last.distanceCm === null || last.distanceCm === undefined || Number.isNaN(last.distanceCm)) {
    node.status({
        fill: "yellow",
        shape: "ring",
        text: "waiting for distance reading"
    });
    return null;
}

const baseline = {
    distanceCm: Number(last.distanceCm),
    capturedAt: now
};

flow.set("baseline", baseline);
flow.set("securityState", "active");

msg.topic = "vehicle/security/status";
msg.payload = {
    armed: true,
    state: "active",
    baseline,
    ts: now
};

node.status({
    fill: "green",
    shape: "dot",
    text: `baseline ${baseline.distanceCm}cm`
});

return msg;

/**
 * Normalize the Pi 2 sensor bundle and update latest cached readings.
 */
const now = Date.now();
const p = msg.payload || {};
const last = flow.get("last") || {};

if (p.vibration !== undefined) {
    last.vibration = Number(p.vibration);
    last.vibrationAt = p.ts || now;
}

if (p.accel) {
    const x = Number(p.accel.x || 0);
    const y = Number(p.accel.y || 0);
    const z = Number(p.accel.z || 0);
    last.accelMag = Math.sqrt((x * x) + (y * y) + (z * z));
    last.accelAt = p.ts || now;
}

flow.set("last", last);

msg.payload = {
    sensor: "pi2_bundle",
    vibration: last.vibration,
    accelMag: last.accelMag,
    ts: p.ts || now
};

return msg;

/**
 * Unified detection engine for GrovePi 1 and Pi 2 readings.
 * Low-level sensor:
 * - ultrasonic -> suspicious
 *
 * High-level sensors:
 * - vibration
 * - accelerometer magnitude
 *
 * High-level evidence can trigger alarm without seat occupancy.
 */
const now = Date.now();
const armed = Boolean(flow.get("armed"));
let state = flow.get("securityState") || "inactive";
const settings = flow.get("settings") || {};
const baseline = flow.get("baseline") || {};
const last = flow.get("last") || {};
let intrusion = flow.get("intrusion") || {};
const resolvedUntil = flow.get("resolvedUntil");

if (!armed) {
    return null;
}

/**
 * Return resolved mode back to active after the short display window.
 */
if (state === "resolved" && resolvedUntil && now >= resolvedUntil) {
    flow.set("securityState", "active");
    flow.set("resolvedUntil", null);

    const currentIntrusion = flow.get("intrusion") || {};
    if (currentIntrusion.status === "resolved" || currentIntrusion.status === "timed_out") {
        flow.set("intrusion", {
            id: null,
            startedAt: null,
            lastEvidenceAt: null,
            confirmedBy: [],
            status: "closed",
            picturePath: null,
            videoPath: null,
            videoActive: false,
            note: null,
            closedAt: currentIntrusion.closedAt || now
        });
    }

    state = "active";
}

/**
 * Wait until baseline exists before evaluating occupancy.
 */
if (baseline.distanceCm === null || baseline.distanceCm === undefined) {
    return null;
}

const recent = (timestamp, maxMs) => Boolean(timestamp) && ((now - timestamp) <= maxMs);

const seatDelta = Math.abs((last.distanceCm ?? baseline.distanceCm) - baseline.distanceCm);
const seatTriggered = seatDelta >= settings.seatDeltaCm;

let seatStableSince = flow.get("seatStableSince") || null;
if (seatTriggered) {
    if (!seatStableSince) {
        seatStableSince = now;
        flow.set("seatStableSince", seatStableSince);
    }
} else {
    flow.set("seatStableSince", null);
    seatStableSince = null;
}

const seatDebounced = Boolean(seatStableSince) && ((now - seatStableSince) >= settings.seatDebounceMs);

const vibrationTriggered =
    Number(last.vibration || 0) >= settings.vibrationSpike &&
    recent(last.vibrationAt, settings.confirmWindowMs);

const accelTriggered =
    Number(last.accelMag || 0) >= settings.accelMagSpike &&
    recent(last.accelAt, settings.confirmWindowMs);

const lowEvidence = [];
const highEvidence = [];

if (seatDebounced) lowEvidence.push("ultrasonic");
if (vibrationTriggered) highEvidence.push("vibration");
if (accelTriggered) highEvidence.push("accel");

const allEvidence = [...lowEvidence, ...highEvidence];
const suspiciousModeEnabled = Boolean(settings.suspiciousModeEnabled);

const ensureOpenIntrusion = () => {
    if (!intrusion.id || intrusion.status !== "open") {
        intrusion = {
            id: `intr_${now}`,
            startedAt: now,
            lastEvidenceAt: now,
            confirmedBy: [],
            status: "open",
            picturePath: null,
            videoPath: null,
            note: null,
            closedAt: null
        };
    } else {
        intrusion.lastEvidenceAt = now;
    }
};

let event = null;
let nextState = state;

/**
 * ACTIVE -> SUSPICIOUS or ALARM
 */
if (state === "active") {
    const shouldAlarmImmediately =
        highEvidence.length >= 1 || (lowEvidence.length >= 1 && highEvidence.length >= 1);

    if (shouldAlarmImmediately || (!suspiciousModeEnabled && lowEvidence.length >= 1)) {
        ensureOpenIntrusion();
        intrusion.confirmedBy = Array.from(new Set([...(intrusion.confirmedBy || []), ...allEvidence]));
        nextState = "alarm";
        event = {
            type: "ALARM_ON",
            reason: shouldAlarmImmediately ? "high_level_sensor" : "suspicious_mode_disabled",
            intrusionId: intrusion.id,
            evidence: intrusion.confirmedBy,
            state: nextState,
            ts: now
        };
    } else if (lowEvidence.length >= 1 && suspiciousModeEnabled) {
        ensureOpenIntrusion();
        intrusion.confirmedBy = Array.from(new Set([...(intrusion.confirmedBy || []), ...lowEvidence]));
        nextState = "suspicious";
        event = {
            type: "INFO_SUSPICIOUS",
            reason: "seat_delta",
            intrusionId: intrusion.id,
            evidence: intrusion.confirmedBy,
            state: nextState,
            ts: now
        };
    }
}

/**
 * SUSPICIOUS -> ALARM or timeout back to ACTIVE
 */
else if (state === "suspicious") {
    ensureOpenIntrusion();

    if (highEvidence.length >= 1) {
        intrusion.confirmedBy = Array.from(new Set([...(intrusion.confirmedBy || []), ...allEvidence]));
        nextState = "alarm";
        event = {
            type: "ALARM_ON",
            reason: "confirmed_after_suspicious",
            intrusionId: intrusion.id,
            evidence: intrusion.confirmedBy,
            state: nextState,
            ts: now
        };
    } else if ((now - intrusion.startedAt) >= settings.suspiciousTimeoutMs) {
        intrusion.status = "timed_out";
        intrusion.closedAt = now;
        nextState = "active";
        event = {
            type: "ALARM_OFF",
            reason: "suspicious_timeout",
            intrusionId: intrusion.id,
            evidence: intrusion.confirmedBy || [],
            picturePath: intrusion.picturePath || "",
            videoPath: intrusion.videoPath || "",
            state: nextState,
            ts: now
        };
    }
}

/**
 * Ignore detection while already in alarm.
 */
else if (state === "alarm") {
    if (intrusion.id && intrusion.status === "open") {
        intrusion.lastEvidenceAt = now;
        intrusion.confirmedBy = Array.from(new Set([...(intrusion.confirmedBy || []), ...allEvidence]));
        flow.set("intrusion", intrusion);
    }
    return null;
}

if (!event) {
    return null;
}

flow.set("securityState", nextState);

if (event.type === "ALARM_OFF" && event.reason === "suspicious_timeout") {
    flow.set("intrusion", intrusion);
} else {
    flow.set("intrusion", intrusion);
}

return {
    event,
    statusUpdate: {
        armed: true,
        state: nextState,
        intrusionId: event.intrusionId || intrusion.id || null,
        evidence: intrusion.confirmedBy || [],
        ts: now
    }
};

/**
 * Start local alarm flashing/buzzing cycle.
 */
flow.set("alarm", {
    active: true,
    tickCount: 0,
    ledState: 0
});

return msg;

/**
 * Stop local alarm devices and reset state.
 */
flow.set("alarm", {
    active: false,
    tickCount: 0,
    ledState: 0
});

return [
    { payload: 0 },
    { payload: 0 },
    { reset: true }
];

/**
 * Alternate LED state and pulse buzzer while the alarm is active.
 */
const alarm = flow.get("alarm") || { active: false, tickCount: 0, ledState: 0 };

if (!alarm.active) {
    return [null, null];
}

alarm.tickCount += 1;
alarm.ledState = alarm.ledState ? 0 : 1;
flow.set("alarm", alarm);

return [
    { payload: 1 },
    { payload: alarm.ledState }
];

/**
 * Camera policy:
 * - INFO_SUSPICIOUS: capture a still image only
 * - ALARM_ON: start video recording as .h264
 * - ALARM_OFF: stop recording and convert .h264 -> .mp4
 *
 * Outputs:
 * 1 = Exec node
 * 2 = Dashboard live feed
 * 3 = Event persistence
 */
const event = msg.event || {};
const baseDir = "/home/pi/autoguard";
const scriptPath = `${baseDir}/camera_service.py`;

let intrusion = flow.get("intrusion") || {
    id: null,
    startedAt: null,
    lastEvidenceAt: null,
    confirmedBy: [],
    status: "closed",
    picturePath: null,
    videoPath: null,
    videoActive: false,
    note: null,
    closedAt: null
};

const activeIntrusionId = event.intrusionId || intrusion.id || null;

const imagePath = activeIntrusionId ? `${baseDir}/images/${activeIntrusionId}.jpg` : (intrusion.picturePath || "");
const h264Path = activeIntrusionId ? `${baseDir}/videos/${activeIntrusionId}.h264` : "";
const mp4Path = activeIntrusionId ? `${baseDir}/videos/${activeIntrusionId}.mp4` : (intrusion.videoPath || "");
const pidPath = activeIntrusionId ? `${baseDir}/videos/${activeIntrusionId}.pid` : "";
const logPath = activeIntrusionId
    ? `/tmp/autoguard_camera_${activeIntrusionId}.log`
    : `/tmp/autoguard_camera_generic.log`;

const liveFeedMsg = RED.util.cloneMessage(msg);
const persistenceMsg = RED.util.cloneMessage(msg);
let execMsg = null;

// Suspicious -> capture picture only
if (event.type === "INFO_SUSPICIOUS") {
    if (!activeIntrusionId) {
        return [null, null, null];
    }

    intrusion.id = intrusion.id || activeIntrusionId;
    intrusion.picturePath = intrusion.picturePath || imagePath;
    intrusion.videoPath = intrusion.videoPath || mp4Path;
    intrusion.videoActive = false;
    flow.set("intrusion", intrusion);

    liveFeedMsg.event.picturePath = intrusion.picturePath;
    liveFeedMsg.event.videoPath = intrusion.videoPath || "";

    persistenceMsg.event.picturePath = intrusion.picturePath;
    persistenceMsg.event.videoPath = intrusion.videoPath || "";

    execMsg = RED.util.cloneMessage(msg);
    execMsg.payload = `-lc "python3 ${scriptPath} capture-image --output '${intrusion.picturePath}' >'${logPath}' 2>&1"`;

    return [execMsg, liveFeedMsg, persistenceMsg];
}

// Alarm -> start video recording as h264
if (event.type === "ALARM_ON") {
    if (!activeIntrusionId) {
        return [null, null, null];
    }

    intrusion.id = intrusion.id || activeIntrusionId;
    intrusion.picturePath = intrusion.picturePath || imagePath;
    intrusion.videoPath = intrusion.videoPath || mp4Path;
    intrusion.videoActive = true;
    flow.set("intrusion", intrusion);

    liveFeedMsg.event.picturePath = intrusion.picturePath;
    liveFeedMsg.event.videoPath = intrusion.videoPath;

    persistenceMsg.event.picturePath = intrusion.picturePath;
    persistenceMsg.event.videoPath = intrusion.videoPath;

    execMsg = RED.util.cloneMessage(msg);
    execMsg.payload = `-lc "python3 ${scriptPath} start-video --output '${h264Path}' --pid-file '${pidPath}' >'${logPath}' 2>&1 &"`;

    return [execMsg, liveFeedMsg, persistenceMsg];
}

// Resolve / timeout / disarm -> stop video and convert to mp4
if (event.type === "ALARM_OFF") {
    liveFeedMsg.event.picturePath = intrusion.picturePath || "";
    liveFeedMsg.event.videoPath = intrusion.videoPath || "";

    persistenceMsg.event.picturePath = intrusion.picturePath || "";
    persistenceMsg.event.videoPath = intrusion.videoPath || "";

    if (!intrusion.videoActive || !activeIntrusionId) {
        return [null, liveFeedMsg, persistenceMsg];
    }

    const stopH264Path = `${baseDir}/videos/${activeIntrusionId}.h264`;
    const stopMp4Path = `${baseDir}/videos/${activeIntrusionId}.mp4`;
    const stopPidPath = `${baseDir}/videos/${activeIntrusionId}.pid`;

    intrusion.videoActive = false;
    intrusion.videoPath = stopMp4Path;
    flow.set("intrusion", intrusion);

    execMsg = RED.util.cloneMessage(msg);
    execMsg.payload = `-lc "python3 ${scriptPath} stop-video --pid-file '${stopPidPath}' --h264-input '${stopH264Path}' --mp4-output '${stopMp4Path}' >'${logPath}' 2>&1"`;

    return [execMsg, liveFeedMsg, persistenceMsg];
}

return [null, null, null];

/**
 * Save security events with sensor snapshot context.
 * Falls back to the current intrusion record for media paths.
 */
const event = msg.event || {};
const last = flow.get("last") || {};
const baseline = flow.get("baseline") || {};
const intrusion = flow.get("intrusion") || {};

const picturePath = event.picturePath || intrusion.picturePath || "";
const videoPath = event.videoPath || intrusion.videoPath || "";

msg.payload = {
    measurement: "security_events",
    tags: {
        device: "pi1",
        intrusionId: event.intrusionId || "none",
        type: event.type || "unknown"
    },
    fields: {
        state: String(event.state || flow.get("securityState") || "unknown"),
        reason: String(event.reason || ""),
        evidence: JSON.stringify(event.evidence || []),
        picture_path: String(picturePath),
        video_path: String(videoPath),
        distance_cm: last.distanceCm ?? null,
        baseline_cm: baseline.distanceCm ?? null,
        vibration: last.vibration ?? null,
        accel_mag: last.accelMag ?? null
    },
    timestamp: new Date(event.ts || Date.now())
};

return msg;

/**
 * Convert detection output to the alert payload contract.
 */
if (!msg.event) {
    return null;
}

msg.payload = msg.event;
return msg;

/**
 * Convert detection output to the status payload contract.
 */
if (!msg.statusUpdate) {
    return null;
}

msg.payload = msg.statusUpdate;
return msg;

/**
 * Update configurable system settings.
 * Only approved settings are written back to flow context.
 */
const current = flow.get("settings") || {};
const incoming = msg.payload || {};

const updated = {
    ...current,
    suspiciousModeEnabled: incoming.suspiciousModeEnabled !== undefined
        ? Boolean(incoming.suspiciousModeEnabled)
