 */
const event = msg.event || null;
const intrusion = flow.get("intrusion") || {};

if (!event) {
    return null;
}

const feed = flow.get("liveFeedEvents") || [];

const entry = {
    type: event.type || "UNKNOWN",
    reason: event.reason || "",
    intrusionId: event.intrusionId || null,
    evidence: Array.isArray(event.evidence) ? event.evidence : [],
    state: event.state || (flow.get("securityState") || "inactive"),
    picturePath: event.picturePath || intrusion.picturePath || "",
    videoPath: event.videoPath || intrusion.videoPath || "",
    note: event.note || "",
    ts: event.ts || Date.now()
};

feed.unshift(entry);

flow.set("liveFeedEvents", feed.slice(0, 50));

return null;

/**
 * Build the absolute path for an image request.
 * Only allows safe filenames to prevent path traversal.
 *
 * Outputs:
 * 1 = valid file read request
 * 2 = immediate HTTP error response
 */
const filename = msg.req?.params?.filename || "";

// Allow only simple filenames such as:
// intr_1773108166477.jpg
if (!/^[a-zA-Z0-9._-]+$/.test(filename)) {
    msg.statusCode = 400;
    msg.headers = {
        "Content-Type": "application/json"
    };
    msg.payload = {
        ok: false,
        error: "Invalid filename"
    };
    return [null, msg];
}

msg.filename = "/home/pi/autoguard/images/" + filename;
msg.requestedFile = filename;

return [msg, null];

/**
 * Return image bytes with the correct content type.
 */
const filename = msg.requestedFile || msg.filename || "";

let contentType = "application/octet-stream";

if (filename.endsWith(".jpg") || filename.endsWith(".jpeg")) {
    contentType = "image/jpeg";
} else if (filename.endsWith(".png")) {
    contentType = "image/png";
} else if (filename.endsWith(".webp")) {
    contentType = "image/webp";
}

msg.headers = {
    "Content-Type": contentType,
    "Cache-Control": "no-cache"
};

return msg;

